const body = $input.first().json.body || $input.first().json;
const taskId = body.taskId || '';
const title = body.title || '(无标题)';
const content = body.content || '';
const contentDir = body.contentDir || '';
const platforms = body.targetPlatforms || [];

const supported = ['douyin', 'xiaohongshu'];
const valid = platforms.filter(p => supported.includes(p));

if (valid.length === 0) {
  return [{ json: { skip: true, taskId, title, content, contentDir, reason: '没有支持的平台' } }];
}

return [{ json: { skip: false, taskId, title, content, contentDir, platform: valid[0] } }];

const stdout = $input.first().json.stdout || '';
const prev = $('准备').first().json;

const platformNames = { douyin: '抖音', xiaohongshu: '小红书' };
const platformDisplay = platformNames[prev.platform] || prev.platform;

let success = false;
let error = '';

try {
  const m = stdout.match(/\{[\s\S]*?\}/);
  if (m) {
    const r = JSON.parse(m[0]);
    success = r.success === true;
    error = r.error || '';
  }
} catch (e) {
  error = '解析失败';
}

const emoji = success ? '✅' : '❌';
const status = success ? '发布成功' : '发布失败';
let text = emoji + ' ' + status + '\n';
text += '平台: ' + platformDisplay + '\n';
text += '标题: ' + prev.title;
if (error) text += '\n错误: ' + error;

return [{
  json: {
    taskId: prev.taskId,
    success,
    feishuBody: { msg_type: 'text', content: { text } }
  }
}];

const stdout = $input.first().json.stdout || '';
const prev = $('准备').first().json;

let success = false;
let error = '';

// 优先解析 JSON（脚本输出的结构化结果）
try {
  // 找最后一个 JSON 对象（脚本末尾追加的 {"success":...}）
  const matches = stdout.match(/\{[^{}]*"success"[^{}]*\}/g);
  if (matches && matches.length > 0) {
    const r = JSON.parse(matches[matches.length - 1]);
    if (typeof r.success === 'boolean') success = r.success;
    if (r.error) error = r.error;
  } else {
    // 降级：关键词匹配
    if (stdout.includes('[XHS] ✅') || stdout.includes('发布成功') || stdout.includes('笔记已发布')) {
      success = true;
    } else if (stdout.includes('[XHS] ❌') || stdout.includes('发布失败') || stdout.includes('Error')) {
      success = false;
      const errLine = stdout.split('\n').find(l => l.includes('[XHS] ❌') || l.toLowerCase().includes('error'));
      error = errLine ? errLine.replace(/\[XHS\]\s*❌\s*/, '').trim() : '未知错误';
    } else {
      success = stdout.trim().length > 0;
    }
  }
} catch (e) {
  error = '解析失败: ' + e.message;
}

const emoji = success ? '✅' : '❌';
const status = success ? '发布成功' : '发布失败';
let text = emoji + ' ' + status + '\n';
text += '平台: 小红书\n';
text += '标题: ' + prev.title;
if (error) text += '\n错误: ' + error;

return [{
  json: {
    taskId: prev.taskId,
    success,
    feishuBody: { msg_type: 'text', content: { text } }
  }
}];
